-- Tablón de misiones
lang["#MISSION_BOARD_MPASS"] = "Tablón de Tareas del Paso de Montaña"
lang["#MISSION_BOARD_MPASS_SUBTITLE"] = "Tareas y Trabajos"
lang["#MISSION_BOARD_MPASS_GREET"] = "Este tablón contiene varios papeles con trabajos de personas que buscan contratar a otros en esta área. Puedes aceptar cualquier trabajo que cumpla con los requisitos.\n\n\nA continuación, una lista de trabajos disponibles."

-- Misiones
lang["#MISSION_MPASS_INFESTATION"] = "Infestación"
lang["#MISSION_MPASS_INFESTATION_DESC"] = "El contratista de esta tarea busca a alguien que esté dispuesto a eliminar necrófagos en la región actual. Ofrece una cantidad razonable por ello."
lang["#MISSION_MPASS_INFESTATION_HINT"] = "Elimina cualquier tipo de Necrófago Salvaje en el Paso de Montaña. Se pueden encontrar fácilmente en las carreteras de la región y en casas o cabañas abandonadas."
lang["#MISSION_MPASS_INFESTATION_COMPLETE"] = "Has completado la tarea."

lang["#MISSION_MPASS_LOCALCANNIBALS"] = "Caníbales Locales"
lang["#MISSION_MPASS_LOCALCANNIBALS_DESC"] = "El contratista de esta tarea busca a alguien que vaya a eliminar a los Bandidos Pico de Hielo en la región actual."
lang["#MISSION_MPASS_LOCALCANNIBALS_HINT"] = "Elimina cualquier tipo de Bandido Pico de Hielo en el Paso de Montaña. Se pueden encontrar en campamentos establecidos a lo largo de las carreteras y bosques."
lang["#MISSION_MPASS_LOCALCANNIBALS_COMPLETE"] = "Has completado la tarea."

lang["#MISSION_MPASS_MASTER_BLASTER"] = "Maestro Blaster"
lang["#MISSION_MPASS_MASTER_BLASTER_DESC"] = "Quien puso esto quiere a alguien muy hábil con escopetas para eliminar diferentes tipos de enemigos."
lang["#MISSION_MPASS_MASTER_BLASTER_HINT"] = "Elimina cualquier tipo de Necrófago Salvaje y Gecko con cualquier escopeta. Los Necrófagos Salvajes se pueden encontrar esparcidos por la carretera que conduce a las Tierras de Ceniza. Los Geckos se pueden encontrar comúnmente en Salt Wells."
lang["#MISSION_MPASS_MASTER_BLASTER_COMPLETE"] = "Has completado la tarea."

lang["#MISSION_MPASS_GOLDHILLS"] = "Oro en Estas Colinas"
lang["#MISSION_MPASS_GOLDHILLS_DESC"] = "¡Oye! Llegué hasta aquí porque me dijeron que había una buena cantidad de oro abandonado aquí. Lo necesitamos para algunas de nuestras cosas eléctricas. Me dijeron que ayuda con algo dentro. Consígueme dos lingotes y serás recompensado."
lang["#MISSION_MPASS_GOLDHILLS_HINT"] = "Recoge dos Lingotes de Oro. Se pueden encontrar raramente en cajas fuertes. Esto puede tomar un tiempo completarse."
lang["#MISSION_MPASS_GOLDHILLS_COMPLETE"] = "Buen trabajo, no esperaba que completaras esto. Tu recompensa está a la izquierda, enterrada junto al edificio. Busca la botella de Nuka Cola vacía."

lang["#MISSION_MPASS_SHIPMENTRECOVER"] = "Recuperación de Envío"
lang["#MISSION_MPASS_SHIPMENTRECOVER_DESC"] = "Esta solicitud la hace un tercero anónimo.\n\nHola, a menudo tenemos personas que huyen con cosas que no deberían tener, pero los Picos de Hielo se encargan de ellos rápidamente. Desafortunadamente para nosotros, no están interesados en negociar con nosotros. Por favor, localiza un gran baúl azul, probablemente en uno de sus campamentos, y devuélvelo."
lang["#MISSION_MPASS_SHIPMENTRECOVER_HINT"] = "Busca un baúl tipo vaporera azul en uno de los campamentos de los Picos de Hielo. Puede estar en cualquier lugar, pero algunos están menos defendidos que otros. Prepárate para una pelea."
lang["#MISSION_MPASS_SHIPMENTRECOVER_COMPLETE"] = "Excelente. Elige tu denominación."
lang["#MISSION_MPASS_SHIPMENTRECOVER_ITEMNAME"] = "Baúl Vaporera Cerrado"

lang["#MISSION_MPASS_SAFETRAVELS"] = "Viajes Seguros"
lang["#MISSION_MPASS_SAFETRAVELS_DESC"] = "El paso está comenzando a infestarse de abominaciones, Yao guai y lo peor de todo, bandidos. Necesitamos una purga y necesitamos voluntarios para hacerlo."
lang["#MISSION_MPASS_SAFETRAVELS_HINT"] = "Mata a 20 Yao guai, 40 Necrófagos y 20 Picos de Hielo. Se pueden encontrar por todo el paso."
lang["#MISSION_MPASS_SAFETRAVELS_COMPLETE"] = "Trabajo increíble, no puedo creer que hayas soportado eso."

lang["#MISSION_HUNT_YAOGUAI_BOSS_EASY"] = "En el Vientre de la Bestia"
lang["#MISSION_HUNT_YAOGUAI_BOSS_EASY_DESC"] = "Atención cazadores. Se ha avistado un Yao Guai Enloquecido atacando a los lugareños por todo el paso. Ya ha matado a varios cazadores experimentados. Ven equipado y listo para pelear si planeas acabar con él. Probablemente puedas encontrarlo cerca de la Gruta de Yao Guai si puedes pasar el resto de sus primos."
lang["#MISSION_HUNT_YAOGUAI_BOSS_EASY_HINT"] = "Mata a un Yao Guai Enloquecido. A veces se puede encontrar escondido en la Gruta de Yao Guai."
lang["#MISSION_HUNT_YAOGUAI_BOSS_EASY_COMPLETE"] = "Buen tiro, cazador. Eso es un diablo menos acechando el Paso."

lang["#MISSION_HUNT_YAOGUAI_BOSS_HARD"] = "En los Pinos"
lang["#MISSION_HUNT_YAOGUAI_BOSS_HARD_DESC"] = "Algunos lugareños encontraron un viejo rifle de antes de la guerra y están dispuestos a intercambiarlo si un cazador puede demostrar su valía en una verdadera cacería. Una de las leyendas locales, el Yao Guai Albino, ha estado aterrorizando las montañas locales. A menudo llamado el Yao Guai Enloquecido por los viajeros, debes tener cuidado con la criatura. Debería encontrarse dentro de su guarida la mayor parte del tiempo."
lang["#MISSION_HUNT_YAOGUAI_BOSS_HARD_HINT"] = "Mata a un Yao Guai Enloquecido con un Rifle de Caza. A veces se puede encontrar escondido en la Gruta de Yao Guai."
lang["#MISSION_HUNT_YAOGUAI_BOSS_HARD_COMPLETE"] = "Eres un cazador nato. Toma este rifle, este tubo buffer lo hará funcionar como nuevo. Es tuyo ahora."

lang["#MISSION_HUNT_MIRELURK_KING_DEEP_EASY"] = "La Sombra Bajo Innsmouth"
lang["#MISSION_HUNT_MIRELURK_KING_DEEP_EASY_DESC"] = "Los Mirelurks se han estado reuniendo alrededor de un Rey Mirelurk y está empezando a ser un problema. Salen de sus cuevas de anidación causando todo tipo de problemas a los viajeros. Ve a ver si puedes hacer algo al respecto."
lang["#MISSION_HUNT_MIRELURK_KING_DEEP_EASY_HINT"] = "Mata a un Profundo. Si está presente, se puede encontrar bajo tierra en una cueva acuática."
lang["#MISSION_HUNT_MIRELURK_KING_DEEP_EASY_COMPLETE"] = "Bien hecho, Cazador. Toma, por tus problemas."

lang["#MISSION_HUNT_WENDIGO_BOSS_MTPASS"] = "La Pesadilla en la Nieve"
lang["#MISSION_HUNT_WENDIGO_BOSS_MTPASS_DESC"] = "Hemos tenido informes de una bestia que grita durante las tormentas de nieve, haciendo que la gente desaparezca cuando se escucha. Se está convirtiendo en una historia de fogata. Sin embargo, todas las historias tienen una base de verdad. Necesitamos que averigües sobre estos gritos y te encargues del problema."
lang["#MISSION_HUNT_WENDIGO_BOSS_MTPASS_HINT"] = "Mata al Wendigo que acecha el Paso de Montaña."
lang["#MISSION_HUNT_WENDIGO_BOSS_MTPASS_COMPLETE"] = "¡Gracias! Quizás podamos dormir por la noche al fin."

RELOADSCHEMA = true